values.content:
Create a 7-day social media content calendar for this business:

Business: {{ $json.businessName }}
Industry: {{ $json.industry }}
Brand Tone: {{ $json.brandTone }}
Key Topics: {{ $json.keyTopics }}
Brand Hashtags: {{ $json.brandHashtags }}
Week Starting: {{ $json.weekStarting }}

For EACH of the 7 days (Monday through Sunday), create content in this EXACT JSON format. Return a JSON array of 7 objects:

[
  {
    "day": "Monday",
    "date": "YYYY-MM-DD",
    "theme": "content theme for the day",
    "twitter": {
      "text": "Tweet text (max 280 chars, include 2-3 hashtags)",
      "type": "tip | question | story | stat | promotional"
    },
    "linkedin": {
      "text": "LinkedIn post (300-600 chars, professional tone, include hashtags at end)",
      "type": "thought-leadership | case-study | tip | industry-news | behind-the-scenes"
    },
    "instagram": {
      "caption": "Instagram caption (engaging, with line breaks, emojis, 5-10 hashtags at end)",
      "imagePrompt": "A description of what image/graphic to create for this post",
      "type": "carousel | single-image | reel-script | story"
    }
  }
]

Return ONLY the JSON array, no other text.

parameters.jsCode:
const content = $input.first().json;
let posts;

try {
  // Parse the AI response - handle both direct array and wrapped response
  const responseText = content.message.content;
  posts = JSON.parse(responseText);
} catch (e) {
  // Try to extract JSON from markdown code blocks
  const match = content.message.content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    posts = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse AI response as JSON. Raw: ' + content.message.content.substring(0, 200));
  }
}

// Return each day as a separate item for the Google Sheets node
return posts.map(post => ({
  json: {
    day: post.day,
    date: post.date,
    theme: post.theme,
    twitter_text: post.twitter.text,
    twitter_type: post.twitter.type,
    linkedin_text: post.linkedin.text,
    linkedin_type: post.linkedin.type,
    instagram_caption: post.instagram.caption,
    instagram_image_prompt: post.instagram.imagePrompt,
    instagram_type: post.instagram.type,
    status: 'Draft - Needs Review',
    generated_at: new Date().toISOString()
  }
}));
